import jsPDF from "jspdf";

const fontRegular = "";

const fontBold = "";

const fontItalic = "";

const fontBoldItalic = "";


const styleMap: Record<string, { data: string; style: string }> = {
  normal: { data: fontRegular, style: "normal" },
  bold: { data: fontBold, style: "bold" },
  italic: { data: fontItalic, style: "italic" },
  bolditalic: { data: fontBoldItalic, style: "bolditalic" },
};

export function registerArialFont(doc: jsPDF): void {
  for (const [key, { data, style }] of Object.entries(styleMap)) {
    doc.addFileToVFS(`Arial-${key}.ttf`, data);
    doc.addFont(`Arial-${key}.ttf`, "Arial", style);
  }
}
